SELECT * FROM package
WHERE waybill_no = #{waybillNo} AND status = #{status}
LIMIT 1

SELECT * FROM package


        AND phone_suffix = #{phone}


        AND (waybill_no LIKE CONCAT('%', #{waybillNo}, '%')
             OR phone LIKE CONCAT('%', #{waybillNo}, '%')
             OR courier LIKE CONCAT('%', #{waybillNo}, '%')
             OR pickup_code LIKE CONCAT('%', #{waybillNo}, '%'))


        AND status = #{status}


ORDER BY create_time DESC
LIMIT #{offset}, #{limit}

SELECT COUNT(*) FROM package
AND phone_suffix = #{phone}
AND (waybill_no LIKE CONCAT('%', #{waybillNo}, '%') OR phone LIKE CONCAT('%', #{waybillNo}, '%') OR courier LIKE CONCAT('%', #{waybillNo}, '%') OR pickup_code LIKE CONCAT('%', #{waybillNo}, '%'))
AND status = #{status}
